    <canvas id="sand" width="400" height="400"></canvas>
    <script>
        const w = 80;
        const h = 80;
        let grid = [];

        function initGrid() {
            for (let y = 0; y < h; y++) {
                grid[y] = [];
                for (let x = 0; x < w; x++) {
                    grid[y][x] = 'empty';
                }
            }
