        function deepCopyGrid(grid) {
            return grid.map(row => row.slice());
        }

        function simulateStep() {
            const tempGrid = deepCopyGrid(grid);
            for (let y = h - 2; y >= 0; y--) {
                for (let x = 0; x < w; x++) {
                    const mat = grid[y][x];
                    if (mat === 'sand') {
                        let moved = false;
                        if (y + 1 < h) {
                            const belowMat = grid[y + 1][x];
                            if (belowMat === 'empty') {
                                tempGrid[y][x] = 'empty';
                                tempGrid[y + 1][x] = 'sand';
                                moved = true;
                            } else if (['water', 'acid'].includes(belowMat)) {
                                tempGrid[y][x] = belowMat;
                                tempGrid[y + 1][x] = 'sand';
                                moved = true;
                            } else {
                                const directions = [-1, 1];
                                if (Math.random() < 0.5) directions.reverse();
                                for (let d of directions) {
                                    let nx = x + d;
                                    let ny = y + 1;
                                    if (nx >= 0 && nx < w && grid[ny][nx] === 'empty') {
                                        tempGrid[y][x] = 'empty';
                                        tempGrid[ny][nx] = 'sand';
                                        moved = true;
                                        break;
                                    }
                                }
                            }
                        }
                    } else if (mat === 'water') {
                        let moved = false;
                        if (y + 1 < h) {
                            const belowMat = grid[y + 1][x];
                            if (belowMat === 'empty') {
                                tempGrid[y][x] = 'empty';
                                tempGrid[y + 1][x] = 'water';
                                moved = true;
                            } else {
                                const directions = [-1, 1];
                                if (Math.random() < 0.5) directions.reverse();
                                for (let d of directions) {
                                    let nx = x + d;
                                    if (nx >= 0 && nx < w && grid[y][nx] === 'empty') {
                                        tempGrid[y][x] = 'empty';
                                        tempGrid[y][nx] = 'water';
                                        moved = true;
                                        break;
                                    }
                                }
                            }
                        }
                    } else if (mat === 'acid') {
                        let newX = x, newY = y;
                        let moved = false;
                        if (y + 1 < h) {
                            const belowMat = grid[y + 1][x];
                            if (belowMat === 'empty') {
                                tempGrid[y][x] = 'empty';
                                tempGrid[y + 1][x] = 'acid';
                                newX = x;
                                newY = y + 1;
                                moved = true;
                            } else {
                                const directions = [-1, 1];
                                if (Math.random() < 0.5) directions.reverse();
                                for (let d of directions) {
                                    let nx = x + d;
                                    if (nx >= 0 && nx < w && grid[y][nx] === 'empty') {
                                        tempGrid[y][x] = 'empty';
                                        tempGrid[y][nx] = 'acid';
                                        newX = nx;
                                        newY = y;
                                        moved = true;
                                        break;
                                    }
                                }
                            }

                            const dissolvePositions = [
                                { dx: 0, dy: 1 },
                                { dx: -1, dy: 0 },
                                { dx: 1, dy: 0 }
                            ];
                            for (let pos of dissolvePositions) {
                                let cx = newX + pos.dx;
                                let cy = newY + pos.dy;
                                if (cx >= 0 && cx < w && cy >= 0 && cy < h) {
                                    const targetMat = grid[cy][cx];
                                    if (targetMat === 'sand' || targetMat === 'wall') {
                                        tempGrid[cy][cx] = 'empty';
                                    }
                                }
                            }
                        }
                    } else if (mat === 'wall') {
                        // No movement
                    }
                }
            }
            grid = tempGrid;
        }

        function getColor(mat) {
            switch (mat) {
                case 'sand': return '#FFC107';
                case 'water': return '#2196F3';
                case 'wall': return '#4CAF50';
                case 'acid': return '#f44336';
                default: return '#000';
            }
        }

        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d');

        function render() {
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    ctx.fillStyle = getColor(grid[y][x]);
                    ctx.fillRect(x * 5, y * 5, 5, 5);
                }
            }
        }

        let currentMat = 'sand';
        let isPainting = false;

        document.getElementById('mat-sand').addEventListener('click', () => { currentMat = 'sand'; });
        document.getElementById('mat-water').addEventListener('click', () => { currentMat = 'water'; });
        document.getElementById('mat-wall').addEventListener('click', () => { currentMat = 'wall'; });
        document.getElementById('mat-acid').addEventListener('click', () => { currentMat = 'acid'; });
        document.getElementById('mat-empty').addEventListener('click', () => { currentMat = 'empty'; });
        document.getElementById('clear').addEventListener('click', () => {
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    grid[y][x] = 'empty';
                }
            }
            render();
        });

        canvas.addEventListener('mousedown', e => {
            isPainting = true;
            updateCanvas(e);
        });
        canvas.addEventListener('mousemove', e => {
            if (isPainting) updateCanvas(e);
        });
        canvas.addEventListener('mouseup', () => { isPainting = false; });
        canvas.addEventListener('mouseleave', () => { isPainting = false; });

        function updateCanvas(e) {
            const rect = canvas.getBoundingClientRect();
            const x = Math.floor((e.clientX - rect.left) * w / rect.width);
            const y = Math.floor((e.clientY - rect.top) * h / rect.height);
            if (x >= 0 && x < w && y >= 0 && y < h) {
                grid[y][x] = currentMat;
            }
        }

        initGrid();
        render();

        window.sim = {
            w,
            h,
            tick(n) {
                for (let i = 0; i < n; i++) simulateStep();
            },
            get(x, y) {
                if (x >= 0 && x < w && y >= 0 && y < h) return grid[y][x];
                return 'empty';
            },
            set(x, y, material) {
                if (x >= 0 && x < w && y >= 0 && y < h) {
                    grid[y][x] = material;
                }
            },
            clear() {
                for (let y = 0; y < h; y++) {
                    for (let x = 0; x < w; x++) {
                        grid[y][x] = 'empty';
                    }
                }
            }
        };

        function animate() {
            requestAnimationFrame(animate);
            simulateStep();
            render();
        }
        animate();
    </script>
