<body>
    <div class="controls">
        <button id="mat-sand" class="material-btn">Sand</button>
        <button id="mat-water" class="material-btn">Water</button>
        <button id="mat-wall" class="material-btn">Wall</button>
        <button id="mat-acid" class="material-btn">Acid</button>
        <button id="mat-empty" class="material-btn">Erase</button>
        <button id="clear" class="material-btn">Clear All</button>
    </div>
    <canvas id="sand"></canvas>

    <script>
        const CELL_SIZE = 5;
        const GRID_W = 80;
        const GRID_H = 80;

        const canvas = document.getElementById('sand');
        canvas.width = GRID_W * CELL_SIZE;
        canvas.height = GRID_H * CELL_SIZE;
        const ctx = canvas.getContext('2d');

        window.sim = {
            w: GRID_W,
            h: GRID_H,
            grid: Array.from({length: GRID_H}, () => Array(GRID_W).fill('empty')),
            tick(n) {
                for (let i = 0; i < n; i++) {
                    const originalGrid = this.grid.map(row => row.slice());
                    const newGrid = JSON.parse(JSON.stringify(originalGrid));

                    for (let y = this.h - 1; y >= 0; y--) {
                        for (let x = 0; x < this.w; x++) {
                            const material = originalGrid[y][x];
                            if (material === 'empty' || material === 'wall') continue;

                            switch(material) {
                                case 'sand':
                                    {
                                        const belowY = y + 1;
                                        if (belowY < this.h) {
                                            const belowMat = originalGrid[belowY][x];
                                            if (['empty', 'water', 'acid'].includes(belowMat)) {
                                                newGrid[y][x] = 'empty';
                                                newGrid[belowY][x] = 'sand';
                                                continue;
                                            }
                                        }

                                        let directions;
                                        if (Math.random() < 0.5) {
                                            directions = ['left', 'right'];
                                        } else {
                                            directions = ['right', 'left'];
                                        }
                                        for (const dir of directions) {
                                            const nx = x + (dir === 'left' ? -1 : 1);
                                            if (nx >= 0 && nx < this.w) {
                                                const belowY2 = y + 1;
                                                if (belowY2 < this.h) {
                                                    const targetMat = originalGrid[belowY2][nx];
                                                    if (['empty', 'water', 'acid'].includes(targetMat)) {
                                                        newGrid[y][x] = 'empty';
                                                        newGrid[belowY2][nx] = 'sand';
                                                        break;
                                                    }
                                                }
                                            }
                                        }
                                    }
                                    break;

                                case 'water':
                                    {
                                        const belowY = y + 1;
                                        if (belowY < this.h) {
                                            const belowMat = originalGrid[belowY][x];
                                            if (['empty', 'sand', 'acid'].includes(belowMat)) {
                                                newGrid[y][x] = 'empty';
                                                newGrid[belowY][x] = 'water';
                                                continue;
                                            }
                                        }

                                        let directionsH;
                                        if (Math.random() < 0.5) {
                                            directionsH = ['left', 'right'];
                                        } else {
                                            directionsH = ['right', 'left'];
                                        }
                                        for (const dir of directionsH) {
                                            const nx = x + (dir === 'left' ? -1 : 1);
                                            if (nx >= 0 && nx < this.w) {
                                                const targetMat = originalGrid[y][nx];
                                                if (targetMat === 'empty') {
                                                    newGrid[y][x] = 'empty';
                                                    newGrid[y][nx] = 'water';
                                                    break;
                                                }
                                            }
                                        }
                                    }
                                    break;

                                case 'acid':
                                    {
                                        let moved = false;
                                        const belowY1 = y + 1;
                                        if (belowY1 < this.h) {
                                            const belowMat = originalGrid[belowY1][x];
                                            if (['empty', 'sand', 'water'].includes(belowMat)) {
                                                newGrid[y][x] = 'empty';
                                                newGrid[belowY1][x] = 'acid';
                                                moved = true;
                                            } else {
                                                let directionsH;
                                                if (Math.random() < 0.5) {
                                                    directionsH = ['left', 'right'];
                                                } else {
                                                    directionsH = ['right', 'left'];
                                                }
                                                for (const dir of directionsH) {
                                                    const nx = x + (dir === 'left' ? -1 : 1);
                                                    if (nx >= 0 && nx < this.w) {
                                                        const targetMat = originalGrid[y][nx];
                                                        if (targetMat === 'empty') {
                                                            newGrid[y][x] = 'empty';
                                                            newGrid[y][nx] = 'acid';
                                                            moved = true;
                                                            break;
                                                        }
                                                    }
                                                }
                                            }
                                        }

                                        let nxAcid = x, nyAcid = y;
                                        if (moved) {
                                            if (originalGrid[belowY1][x] === 'empty' || 
                                                originalGrid[belowY1][x] === 'sand' || 
                                                originalGrid[belowY1][x] === 'water') {
                                                nyAcid = belowY1;
                                                nxAcid = x;
                                            } else {
                                                for (const dir of directionsH) {
                                                    const tx = x + (dir === 'left' ? -1 : 1);
                                                    if (tx >=0 && tx < this.w) {
                                                        const targetMat = originalGrid[y][tx];
                                                        if (targetMat === 'empty') {
                                                            nxAcid = tx;
                                                            nyAcid = y;
                                                            break;
                                                        }
                                                    }
                                                }
                                            }
                                        }

                                        const downY = nyAcid + 1;
                                        if (downY < this.h) {
                                            const cellDown = originalGrid[downY][nxAcid];
                                            if (cellDown === 'sand' || cellDown === 'wall') {
                                                newGrid[downY][nxAcid] = 'empty';
                                            }
                                        }

                                        const leftX = nxAcid - 1;
                                        if (leftX >=0) {
                                            const cellLeft = originalGrid[nyAcid][leftX];
                                            if (cellLeft === 'sand' || cellLeft === 'wall') {
                                                newGrid[nyAcid][leftX] = 'empty';
                                            }
                                        }

                                        const rightX = nxAcid + 1;
                                        if (rightX < this.w) {
                                            const cellRight = originalGrid[nyAcid][rightX];
                                            if (cellRight === 'sand' || cellRight === 'wall') {
                                                newGrid[nyAcid][rightX] = 'empty';
                                            }
                                        }
                                    }
                                    break;
                            }
                        }
                    }

                    this.grid = newGrid;
                }
            },
            get(x, y) {
                if (x < 0 || x >= this.w || y < 0 || y >= this.h) return 'empty';
                return this.grid[y][x];
            },
            set(x, y, material) {
                if (x >= 0 && x < this.w && y >= 0 && y < this.h) {
                    this.grid[y][x] = material;
                }
            },
            clear() {
                for (let y = 0; y < this.h; y++) {
                    for (let x = 0; x < this.w; x++) {
                        this.grid[y][x] = 'empty';
                    }
                }
            }
        };

        let currentMaterial = 'sand';

        document.getElementById('mat-sand').addEventListener('click', () => { currentMaterial = 'sand'; });
        document.getElementById('mat-water').addEventListener('click', () => { currentMaterial = 'water'; });
        document.getElementById('mat-wall').addEventListener('click', () => { currentMaterial = 'wall'; });
        document.getElementById('mat-acid').addEventListener('click', () => { currentMaterial = 'acid'; });
        document.getElementById('mat-empty').addEventListener('click', () => { currentMaterial = 'empty'; });
        document.getElementById('clear').addEventListener('click', () => {
            window.sim.clear();
            draw();
        });

        canvas.addEventListener('mousedown', (e) => {
            const rect = canvas.getBoundingClientRect();
            let mouseX = e.clientX - rect.left;
            let mouseY = e.clientY - rect.top;

            const x = Math.floor(mouseX / CELL_SIZE);
            const y = Math.floor(mouseY / CELL_SIZE);

            window.sim.set(x, y, currentMaterial);
            draw();

            function onMouseMove(e) {
                const mx = e.clientX - rect.left;
                const my = e.clientY - rect.top;

                const xCell = Math.floor(mx / CELL_SIZE);
                const yCell = Math.floor(my / CELL_SIZE);

                window.sim.set(xCell, yCell, currentMaterial);
                draw();
            }

            function onMouseUp() {
                canvas.removeEventListener('mousemove', onMouseMove);
                canvas.removeEventListener('mouseup', onMouseUp);
            }

            canvas.addEventListener('mousemove', onMouseMove);
            canvas.addEventListener('mouseup', onMouseUp);
        });

        function draw() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let y = 0; y < window.sim.h; y++) {
                for (let x = 0; x < window.sim.w; x++) {
                    const mat = window.sim.get(x, y);
                    let color;
                    switch(mat) {
                        case 'sand': color = '#f5c31a'; break;
                        case 'water': color = '#4ec0cf'; break;
                        case 'wall': color = '#888'; break;
                        case 'acid': color = '#7fff00'; break;
                        default: color = 'transparent';
                    }
                    ctx.fillStyle = color;
                    ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                }
            }
        }

        draw();

        let isRunning = true;
        function animate() {
            if (isRunning) {
                window.sim.tick(5);
                draw();
            }
            requestAnimationFrame(animate);
        }

        animate();
    </script>
</body>
